import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { loginUser, verifyAdmin2Fa } from '../utils/api';

function Login({ onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [otp, setOtp] = useState("");
  const [is2FaStep, setIs2FaStep] = useState(false);
  const navigate = useNavigate();

  function handleSubmit(e) {
    e.preventDefault();
    if (!is2FaStep) {
      loginUser(username, password).then(res => {
        if (res.error) return alert(res.error);
        if (res.requires2Fa) {
          setIs2FaStep(true);
          alert("2FA Verification Passcode code dispatched to registered mail account parameters.");
        } else {
          onLogin(res);
          navigate("/");
        }
      });
    } else {
      verifyAdmin2Fa(username, otp).then(res => {
        if (res.error) return alert(res.error);
        onLogin(res);
        navigate("/admin");
      });
    }
  }

  return (
    <div className="login-panel" style={{ padding: "30px", maxWidth: "400px", margin: "auto" }}>
      <h2>{is2FaStep ? "🔒 Enter 2FA OTP Code" : "Account Session Sign-In"}</h2>
      <form onSubmit={handleSubmit}>
        {!is2FaStep ? (
          <>
            <input type="text" placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px" }} required />
            <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px" }} required />
          </>
        ) : (
          <input type="text" placeholder="6-Digit OTP verification passcode code" value={otp} onChange={e => setOtp(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px" }} required />
        )}
        <button type="submit" style={{ width: "100%", padding: "10px", background: "#007bff", color: "#fff", border: "none" }}>
          {is2FaStep ? "Verify Authorization Code" : "Login Securely"}
        </button>
      </form>
    </div>
  );
}

export default Login;
